// Parse first pass response
const apiResponse = $input.first().json;
let classificationData;

try {
  let content = apiResponse.content?.[0]?.text || '';
  content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

  const jsonObjects = [];
  let depth = 0;
  let jsonStart = -1;

  for (let i = 0; i < content.length; i++) {
    if (content[i] === '{') {
      if (depth === 0) jsonStart = i;
      depth++;
    } else if (content[i] === '}') {
      depth--;
      if (depth === 0 && jsonStart !== -1) {
        jsonObjects.push(content.substring(jsonStart, i + 1));
        jsonStart = -1;
      }
    }
  }

  classificationData = JSON.parse(jsonObjects[jsonObjects.length - 1]);
} catch (e) {
  return [{
    json: {
      success: false,
      error: 'Failed to parse first pass response'
    }
  }];
}

return [{
  json: {
    success: true,
    classification: classificationData,
    api_usage: {
      model: apiResponse.model,
      input_tokens: apiResponse.usage?.input_tokens || 0,
      output_tokens: apiResponse.usage?.output_tokens || 0
    }
  }
}];

// Filter questions based on classification
const firstPassResult = $input.first().json;
const referenceData = $('Load Reference Documents').first().json;

if (!firstPassResult.success) {
  return [{
    json: {
      success: false,
      error: 'First pass classification failed'
    }
  }];
}

const primaryCategory = firstPassResult.classification.task_classification?.primary_category;
const secondaryCategory = firstPassResult.classification.task_classification?.secondary_category;
const complexity = firstPassResult.classification.task_classification?.complexity;

// Load universal questions (always included)
let selectedQuestions = referenceData.universal_questions.content;

// Load category-specific questions
const categoryMap = {
  'DECISION': 'decision_questions',
  'STRATEGY': 'strategy_questions',
  'ANALYSIS': 'analysis_questions',
  'CREATION_CONTENT': 'creation_content_questions',
  'CREATION_TECHNICAL': 'creation_technical_questions',
  'IDEATION': 'ideation_questions',
  'PROBLEM_SOLVING': 'problem_solving_questions',
  'LEARNING': 'learning_questions',
  'PERSUASION': 'persuasion_questions',
  'FEEDBACK': 'feedback_questions',
  'RESEARCH': 'research_questions',
  'GOAL_SETTING': 'goal_setting_questions'
};

// Include primary category questions
if (categoryMap[primaryCategory] && referenceData[categoryMap[primaryCategory]]) {
  selectedQuestions += '\n\n' + referenceData[categoryMap[primaryCategory]].content;
}

// Include secondary category questions (if different from primary)
if (secondaryCategory && secondaryCategory !== primaryCategory && categoryMap[secondaryCategory] && referenceData[categoryMap[secondaryCategory]]) {
  selectedQuestions += '\n\n' + referenceData[categoryMap[secondaryCategory]].content;
}

return [{
  json: {
    category: primaryCategory,
    complexity,
    selected_questions: selectedQuestions,
    classification: firstPassResult.classification
  }
}];

