// Parse second pass response and combine results from both passes
const apiResponse = $input.first().json;
const firstPassClassification = $('Prepare Prompt 2').first().json.classification;
const firstPassApiResponse = $('First Pass: Call Anthropic API').first().json;

let questionsData;
try {
  let content = apiResponse.content?.[0]?.text || '';
  content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

  const jsonObjects = [];
  let depth = 0;
  let jsonStart = -1;

  for (let i = 0; i < content.length; i++) {
    if (content[i] === '{') {
      if (depth === 0) jsonStart = i;
      depth++;
    } else if (content[i] === '}') {
      depth--;
      if (depth === 0 && jsonStart !== -1) {
        jsonObjects.push(content.substring(jsonStart, i + 1));
        jsonStart = -1;
      }
    }
  }

  questionsData = JSON.parse(jsonObjects[jsonObjects.length - 1]);
} catch (e) {
  return [{
    json: {
      success: false,
      data: null,
      api_usage: null,
      error: {
        message: 'Failed to parse second pass response',
        details: e.message
      },
      error_context: {
        error_type: 'parsing_error',
        failed_node: 'Second Pass: Call Anthropic API',
        timestamp: new Date().toISOString()
      }
    }
  }];
}

// Aggregate API usage from both passes
const apiUsage = [
  {
    model: firstPassApiResponse.model || 'claude-haiku-4-5-20251001',
    input_tokens: firstPassApiResponse.usage?.input_tokens || 0,
    output_tokens: firstPassApiResponse.usage?.output_tokens || 0
  },
  {
    model: apiResponse.model || 'claude-haiku-4-5-20251001',
    input_tokens: apiResponse.usage?.input_tokens || 0,
    output_tokens: apiResponse.usage?.output_tokens || 0
  }
];

// Combine both passes into final response
const finalData = {
  task_classification: firstPassClassification.task_classification,
  cognitive_requirements: firstPassClassification.cognitive_requirements,
  selected_framework: firstPassClassification.selected_framework,
  alternative_frameworks: firstPassClassification.alternative_frameworks,
  clarifying_questions: questionsData.clarifying_questions,
  question_rationale: questionsData.question_rationale,
  personality_tier: questionsData.personality_tier
};

// Add task_trait_alignment if present in second pass response
if (questionsData.task_trait_alignment) {
  finalData.task_trait_alignment = questionsData.task_trait_alignment;
}

// Add personality_adjustments_preview if present in second pass response
if (questionsData.personality_adjustments_preview) {
  finalData.personality_adjustments_preview = questionsData.personality_adjustments_preview;
}

return [{
  json: {
    success: true,
    data: finalData,
    api_usage: apiUsage,
    error: null
  }
}];

// FIRST PASS: Classify task and select framework
const webhookData = $('Webhook Trigger').first().json.body || {};
const referenceData = $('Load Reference Documents').first().json;

const frameworkDoc = referenceData.framework_taxonomy;

// OPTIMISATION: Check if personality data exists BEFORE loading personality doc
// When hasPersonalityData = false, the prompt omits the entire PERSONALITY CALIBRATION section
const hasPersonalityData = !!webhookData.user_context?.personality?.personality_type;
const personalityDoc = hasPersonalityData ? referenceData.personality_calibration : null;

const taskDescription = webhookData.task_description || '';
const userContext = webhookData.user_context || null;
const preAnalysisContext = webhookData.pre_analysis_context || null;
// NOTE: preAnalysisContext is NOT used in first pass intentionally.
// First pass should classify tasks independently, without pre-analysis bias.
// Pre-analysis context is used only in second pass for question generation.

// Build personality section conditionally
const personalitySection = hasPersonalityData && personalityDoc
    ? `\n\n## PERSONALITY CALIBRATION (Reference)\n\n${personalityDoc.content}\n`
    : '';

const systemPrompt = `You are a task classification API. You have access to the complete Framework Taxonomy${hasPersonalityData ? ' and Personality Calibration documentation' : ''}.

## FRAMEWORK TAXONOMY

${frameworkDoc.content}${personalitySection}
---

## YOUR TASK

Analyze the provided task description and:
1. **Classify** into primary and secondary task categories
2. **Identify** primary and secondary cognitive requirements for the task
3. **Select** the single best framework from the taxonomy
4. **Suggest** 2-3 alternative frameworks MOST RELEVANT to this specific task (consider task category, complexity, and cognitive requirements)

Return ONLY valid JSON with this exact schema:
{
  "task_classification":{"primary_category":"...","secondary_category":null,"complexity":"simple|moderate|complex","classification_reasoning":"..."},
  "cognitive_requirements":{"primary":["REQ1"],"secondary":[],"reasoning":"..."},
  "selected_framework":{"name":"...","code":"...","components":["C1","C2","C3"],"rationale":"..."},
  "alternative_frameworks":[{"name":"...","code":"...","when_to_use_instead":"If you..."}]
}

Rules: Include components array. Don't include rationale in alternatives. Use 2nd person in when_to_use_instead. Select alternatives MOST RELEVANT to task (not generic). JSON only.`;

// Build user context summary - ONLY include non-null fields
let userContextSummary = '';
if (userContext) {
  const contextParts = [];

  if (userContext.location && (userContext.location.country || userContext.location.state || userContext.location.city)) {
    const locationParts = [];
    if (userContext.location.country) locationParts.push(userContext.location.country);
    if (userContext.location.state) locationParts.push(userContext.location.state);
    if (userContext.location.city) locationParts.push(userContext.location.city);
    contextParts.push('Location: ' + locationParts.join(', '));
  }

  if (userContext.professional && (userContext.professional.occupation || userContext.professional.industry || userContext.professional.workEnvironment)) {
    const profParts = [];
    if (userContext.professional.occupation) profParts.push(userContext.professional.occupation);
    if (userContext.professional.industry) profParts.push('in ' + userContext.professional.industry);
    if (userContext.professional.workEnvironment) profParts.push('(' + userContext.professional.workEnvironment + ')');
    contextParts.push('Professional: ' + profParts.join(' '));
  }

  if (userContext.team && (userContext.team.teamSize || userContext.team.teamType)) {
    const teamParts = [];
    if (userContext.team.teamSize) teamParts.push(userContext.team.teamSize + ' person team');
    if (userContext.team.teamType) teamParts.push(userContext.team.teamType);
    contextParts.push('Team: ' + teamParts.join(', '));
  }

  if (userContext.budget && (userContext.budget.monthlyBudget)) {
    const budgetStr = userContext.budget.monthlyBudget + (userContext.budget.budgetCurrency ? ' ' + userContext.budget.budgetCurrency : '');
    contextParts.push('Budget: ' + budgetStr);
  }

  if (userContext.tools && Array.isArray(userContext.tools.preferredTools) && userContext.tools.preferredTools.length > 0) {
    contextParts.push('Preferred Tools: ' + userContext.tools.preferredTools.join(', '));
  }

  if (contextParts.length > 0) {
    userContextSummary = '\n\nUser Context:\n' + contextParts.map(p => '- ' + p).join('\n');
  }
}


// Build pre-analysis context display for Claude
let preAnalysisDisplay = '';
if (preAnalysisContext && typeof preAnalysisContext === 'object' && Object.keys(preAnalysisContext).length > 0) {
  preAnalysisDisplay = '\n\nPre-Analysis Context (from workflow_0):';
  for (const [key, contextItem] of Object.entries(preAnalysisContext)) {
    if (contextItem && typeof contextItem === 'object' && contextItem.question) {
      const displayValue = contextItem.answer_label || contextItem.answer;
      preAnalysisDisplay += '\n- ' + contextItem.question + ': ' + displayValue;
    }
  }
}

const userMessage = `Classify this task and select the best framework:

Task: ${taskDescription}${userContextSummary}${preAnalysisDisplay}

Using the framework taxonomy provided, classify the task and recommend the single best framework plus 2-3 alternatives that are MOST RELEVANT to this specific task (consider the task category, complexity, and cognitive requirements when selecting alternatives).`;

return [{
  json: {
    system: systemPrompt,
    messages: [{
      role: 'user',
      content: userMessage
    }]
  }
}];

// SECOND PASS: Generate clarifying questions AND perform Task-Trait Alignment analysis
const webhookData = $('Webhook Trigger').first().json.body || {};
const filterResult = $input.first().json;
const referenceData = $('Load Reference Documents').first().json;

const selectedQuestions = filterResult.selected_questions;

// CRITICAL: Pass FULL user_context when available
const userContext = webhookData.user_context || null;
const taskDescription = webhookData.task_description || 'Not provided';
const preAnalysisContext = webhookData.pre_analysis_context || null;

const classification = filterResult.classification;
const hasPersonality = !!webhookData.user_context?.personality?.personality_type;

// OPTIMISATION: Only load personality doc when personality data exists
const personalityDoc = hasPersonality ? referenceData.personality_calibration : null;

// Build personality section conditionally
const personalitySection = hasPersonality && personalityDoc
    ? `\n\n## PERSONALITY CALIBRATION\n\n${personalityDoc.content}\n`
    : '';

// Conditionally include personality-related output fields
const personalityOutputFields = hasPersonality
    ? `,
  "personality_tier":"full|partial|none",
  "task_trait_alignment":{"amplified":[{"trait":"...","requirement_aligned":"...","reason":"..."}],"counterbalanced":[{"trait":"...","requirement_opposed":"...","reason":"...","injection":"..."}],"neutral":[{"trait":"...","reason":"..."}]},
  "personality_adjustments_preview":["AMPLIFIED:...","COUNTERBALANCED:..."]`
    : '';

const systemPrompt = `You are a question generation${hasPersonality ? ' and Task-Trait Alignment' : ''} API.${hasPersonality ? ' You have access to personality calibration guidelines.' : ''}${personalitySection}
---

## YOUR TASK

Select and adapt clarifying questions from the provided question bank, tailored to this specific task${hasPersonality ? ' and personality type' : ''}.

For each question, explain: (1) Why it's necessary, (2) How it connects to task requirements${hasPersonality ? ' or personality' : ''}.
${hasPersonality ? '\nIf personality data provided: Perform full Task-Trait Alignment (amplified, counterbalanced, neutral traits).\n' : ''}
Return ONLY valid JSON with these fields:
{
  "clarifying_questions": [{"id":"U1","question":"...","purpose":"...","required":true}],
  "question_rationale":"..."${personalityOutputFields}
}

Rules: ${hasPersonality ? 'alignment fields are objects (not strings). adjustments_preview is 2 strings. Use only user\'s actual traits. If no personality: empty arrays.' : 'Select questions relevant to task requirements and complexity.'}`;

let personalityInfo = 'No personality data';
if (hasPersonality) {
  const p = webhookData.user_context.personality;
  const typeLetters = p.personality_type.split('-');
  const mainType = typeLetters[0]; // e.g., "INTP"
  const identity = typeLetters[1]; // e.g., "A" or "T"
  const traits = p.trait_percentages;

  const traitMapping = [
    `${mainType[0]} (${traits.mind}%) - ${mainType[0] === 'I' ? 'Introversion' : 'Extraversion'}`,
    `${mainType[1]} (${traits.energy}%) - ${mainType[1] === 'S' ? 'Sensing' : 'Intuition'}`,
    `${mainType[2]} (${traits.nature}%) - ${mainType[2] === 'T' ? 'Thinking' : 'Feeling'}`,
    `${mainType[3]} (${traits.tactics}%) - ${mainType[3] === 'J' ? 'Judging' : 'Perceiving'}`,
    `${identity} (${traits.identity}%) - ${identity === 'A' ? 'Assertive' : 'Turbulent'}`
  ];

  personalityInfo = `Type: ${p.personality_type}\nTraits (in order I/E, S/N, T/F, J/P, A/T):\n${traitMapping.join('\n')}\n\nIMPORTANT: Only analyze the user's ACTUAL traits listed above. Do NOT make up traits. Do NOT assume the user has traits they don't have.`;
}

// Build user context summary for Claude
let userContextSummary = '';
if (userContext) {
  userContextSummary = '\n\nUser Context:';

  if (userContext.location) {
    userContextSummary += `\nLocation: ${userContext.location.country || ''}${userContext.location.state ? ', ' + userContext.location.state : ''}${userContext.location.city ? ', ' + userContext.location.city : ''}`;
  }

  if (userContext.professional) {
    userContextSummary += `\nProfessional: ${userContext.professional.occupation || 'N/A'} in ${userContext.professional.industry || 'N/A'} (${userContext.professional.workEnvironment || 'N/A'})`;
  }

  if (userContext.team) {
    userContextSummary += `\nTeam: ${userContext.team.teamSize || 'N/A'} person team (${userContext.team.teamType || 'N/A'})`;
  }

  if (userContext.budget) {
    userContextSummary += `\nBudget: ${userContext.budget.monthlyBudget || 'N/A'} ${userContext.budget.budgetCurrency || ''}`;
  }

  if (userContext.tools && Array.isArray(userContext.tools.preferredTools) && userContext.tools.preferredTools.length > 0) {
    userContextSummary += `\nPreferred Tools: ${userContext.tools.preferredTools.join(', ')}`;
  }
}

// Build pre-analysis context display for Claude
let preAnalysisDisplay = '';
if (preAnalysisContext && typeof preAnalysisContext === 'object' && Object.keys(preAnalysisContext).length > 0) {
  preAnalysisDisplay = '\n\nPre-Analysis Context:';
  for (const [key, contextItem] of Object.entries(preAnalysisContext)) {
    if (contextItem && typeof contextItem === 'object' && contextItem.question) {
      const displayValue = contextItem.answer_label || contextItem.answer;
      preAnalysisDisplay += `\n- ${contextItem.question}: ${displayValue}`;
    }
  }
}

const userMessage = `## Question Bank (filtered by task category)

${selectedQuestions}

---

Generate clarifying questions + Task-Trait Alignment:

Task: ${taskDescription}${userContextSummary}${preAnalysisDisplay}

Category: ${classification.task_classification.primary_category} | Reqs: ${classification.cognitive_requirements.primary.join(', ')}${classification.cognitive_requirements.secondary.length > 0 ? ' + ' + classification.cognitive_requirements.secondary.join(', ') : ''} | Complexity: ${classification.task_classification.complexity} | Framework: ${classification.selected_framework.code} | Personality: ${personalityInfo}

Select relevant questions (explain why). If personality: analyze trait alignment. Return all 5 fields.`;

return [{
  json: {
    system: systemPrompt,
    messages: [{
      role: 'user',
      content: userMessage
    }],
    classification: classification,
    cognitive_requirements: classification.cognitive_requirements,
    user_context: userContext
  }
}];
